// jsPDF Font Definition - Arial Unicode
(function () {
  'use strict';
  
  // Base64 encoded, zlib-compressed TTF font
  var fontData = '';
  
  // Register with jsPDF
  if (typeof jsPDF !== 'undefined') {
    jsPDF.API.events.push(function () {
      this.addFont('Arial', 'Arial', 'normal', fontData);
    });
  }
}());
